import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import DatePicker from 'react-datepicker';
import { bookingApi } from '../../api/bookingApi';
import ConflictWarning from './ConflictWarning';
import { ROOMS } from '../../utils/constants';
import 'react-datepicker/dist/react-datepicker.css';

const BookingForm = ({ onSuccess, onCancel }) => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    resourceId: '',
    resourceName: '',
    startTime: new Date(),
    endTime: new Date(),
    purpose: '',
    expectedAttendees: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [conflict, setConflict] = useState({ hasConflict: false, resourceName: '' });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleDateChange = (date, field) => {
    setFormData({ ...formData, [field]: date });
  };

  const setBookingDate = (date) => {
    if (!date) return;

    const nextStart = new Date(formData.startTime);
    nextStart.setFullYear(date.getFullYear(), date.getMonth(), date.getDate());

    const nextEnd = new Date(formData.endTime);
    nextEnd.setFullYear(date.getFullYear(), date.getMonth(), date.getDate());

    setFormData({
      ...formData,
      startTime: nextStart,
      endTime: nextEnd,
    });
  };

  const setStartClockTime = (time) => {
    if (!time) return;
    const next = new Date(formData.startTime);
    next.setHours(time.getHours(), time.getMinutes(), 0, 0);

    let nextEnd = new Date(formData.endTime);
    if (nextEnd <= next) {
      nextEnd = new Date(next);
      nextEnd.setHours(nextEnd.getHours() + 1);
    }

    setFormData({
      ...formData,
      startTime: next,
      endTime: nextEnd,
    });
  };

  const setEndClockTime = (time) => {
    if (!time) return;
    const next = new Date(formData.endTime);
    next.setHours(time.getHours(), time.getMinutes(), 0, 0);

    if (next <= formData.startTime) {
      setError('End time must be after start time');
      return;
    }

    setError(null);
    setFormData({
      ...formData,
      endTime: next,
    });
  };

  const handleResourceChange = (e) => {
    const selectedId = parseInt(e.target.value, 10);
    const selectedRoom = ROOMS.find((room) => room.id === selectedId);

    if (!selectedRoom) {
      setFormData({ ...formData, resourceId: '', resourceName: '' });
      return;
    }

    setFormData({
      ...formData,
      resourceId: selectedRoom.id,
      resourceName: selectedRoom.name,
    });
  };

  const checkConflict = async () => {
    if (!formData.resourceId || !formData.startTime || !formData.endTime) return;
    
    try {
      const result = await bookingApi.checkConflict(
        formData.resourceId,
        formData.startTime.toISOString(),
        formData.endTime.toISOString()
      );
      setConflict({
        hasConflict: result.hasConflict,
        resourceName: formData.resourceName
      });
    } catch (err) {
      console.error('Error checking conflict:', err);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const bookingData = {
        resourceId: parseInt(formData.resourceId),
        resourceName: formData.resourceName,
        startTime: formData.startTime.toISOString(),
        endTime: formData.endTime.toISOString(),
        purpose: formData.purpose,
        expectedAttendees: parseInt(formData.expectedAttendees) || null,
      };

      await bookingApi.createBooking(bookingData);
      if (typeof onSuccess === 'function') {
        onSuccess();
      } else {
        navigate('/bookings/success');
      }
    } catch (err) {
      setError(err.message || 'Failed to create booking');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="booking-page booking-form-page">
      <div className="booking-page-header">
        <div>
          <h1>Create New Booking</h1>
          <p>Reserve campus resources and schedule your next session.</p>
        </div>
      </div>

      <form className="booking-form booking-form-v2" onSubmit={handleSubmit}>
        <div className="booking-form-card">
          <div className="booking-form-card-header">
            <h2>Reservation Details</h2>
            <button
              type="button"
              className="btn-secondary booking-check-btn"
              onClick={checkConflict}
            >
              Check Availability
            </button>
          </div>

          {error && <div className="error-message">{error}</div>}

          <ConflictWarning
            hasConflict={conflict.hasConflict}
            resourceName={conflict.resourceName}
            startTime={formData.startTime}
            endTime={formData.endTime}
          />

          <div className="form-group">
            <label>Select Resource *</label>
            <select
              name="resourceName"
              value={formData.resourceId}
              onChange={handleResourceChange}
              required
            >
              <option value="">Select a room</option>
              {ROOMS.map((room) => (
                <option key={room.id} value={room.id}>
                  {room.name} ({room.type})
                </option>
              ))}
            </select>
            {formData.resourceId && (
              <small className="resource-id-hint">Room ID: {formData.resourceId}</small>
            )}
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Booking Date *</label>
              <DatePicker
                selected={formData.startTime}
                onChange={setBookingDate}
                dateFormat="MM/dd/yyyy"
                minDate={new Date()}
                required
              />
            </div>

            <div className="form-group">
              <label>Expected Attendees</label>
              <input
                type="number"
                name="expectedAttendees"
                value={formData.expectedAttendees}
                onChange={handleChange}
                placeholder="0"
                min="0"
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Start Time *</label>
              <DatePicker
                selected={formData.startTime}
                onChange={setStartClockTime}
                showTimeSelect
                showTimeSelectOnly
                timeIntervals={15}
                timeCaption="Start"
                dateFormat="h:mm aa"
                required
              />
            </div>

            <div className="form-group">
              <label>End Time *</label>
              <DatePicker
                selected={formData.endTime}
                onChange={setEndClockTime}
                showTimeSelect
                showTimeSelectOnly
                timeIntervals={15}
                timeCaption="End"
                dateFormat="h:mm aa"
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label>Purpose of Booking *</label>
            <textarea
              name="purpose"
              value={formData.purpose}
              onChange={handleChange}
              required
              rows="4"
              placeholder="Briefly describe the event or meeting agenda..."
            />
          </div>

          <div className="form-actions booking-form-actions">
            <button
              type="button"
              className="btn-cancel"
              onClick={() => {
                if (typeof onCancel === 'function') {
                  onCancel();
                } else {
                  navigate('/bookings');
                }
              }}
            >
              Cancel
            </button>
            <button type="submit" className="btn-submit" disabled={loading}>
              {loading ? 'Creating...' : 'Create Booking'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

export default BookingForm;
